    phone: str
    password: str
    name: str
    role: str = "passenger"

class UserLogin(BaseModel):
    phone: str
    password: str

class Token(BaseModel):
    access_token: str
    token_type: str

class DriverLocation(BaseModel):
    x: float
    y: float

class DriverStatusUpdate(BaseModel):
    status: str

class OrderCreate(BaseModel):
    pickup_x: float
    pickup_y: float
    pickup_address: str
    dest_x: float
    dest_y: float
    dest_address: str

class OrderCancel(BaseModel):
    reason: str

class RatingCreate(BaseModel):
    score: int
    comment: Optional[str] = None

class AIChatMessage(BaseModel):
    message: str


# ============== Auth Routes ==============

@app.post("/api/auth/register", response_model=dict)
def register(user: UserCreate, db: Session = Depends(get_db)):
    existing = db.query(User).filter(User.phone == user.phone).first()
    if existing:
        raise HTTPException(status_code=400, detail="Phone already registered")
    hashed = pwd_context.hash(user.password)
    new_user = User(phone=user.phone, password_hash=hashed, name=user.name, role=user.role)
    db.add(new_user)
    db.commit()
    db.refresh(new_user)
    if user.role == "driver":
        driver = Driver(user_id=new_user.id, license_plate="", car_model="")
        db.add(driver)
        db.commit()
    return {"id": new_user.id, "message": "User registered successfully"}


@app.post("/api/auth/login", response_model=Token)
def login(user: UserLogin, db: Session = Depends(get_db)):
    db_user = db.query(User).filter(User.phone == user.phone).first()
    if not db_user or not pwd_context.verify(user.password, db_user.password_hash):
        raise HTTPException(status_code=401, detail="Invalid credentials")
    token = create_access_token({"user_id": db_user.id, "role": db_user.role})
    return {"access_token": token, "token_type": "bearer"}


