# ============== Passenger Routes ==============

@app.post("/api/passenger/order")
def create_order(order: OrderCreate, current_user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    if current_user.role != "passenger":
        raise HTTPException(status_code=403, detail="Only passengers can create orders")
    distance = calculate_distance(order.pickup_x, order.pickup_y, order.dest_x, order.dest_y)
    base_price = calculate_base_price(distance)
    multiplier = get_supply_demand_multiplier(db)
    final_price = round(base_price * multiplier, 2)
    new_order = Order(
        passenger_id=current_user.id,
        pickup_x=order.pickup_x, pickup_y=order.pickup_y, pickup_address=order.pickup_address,
        dest_x=order.dest_x, dest_y=order.dest_y, dest_address=order.dest_address,
        distance=round(distance, 2), base_price=base_price, dynamic_multiplier=multiplier,
        final_price=final_price, estimated_wait=300
    )
    db.add(new_order)
    db.commit()
    db.refresh(new_order)
    dispatch_order(new_order.id, db)
    return {
        "order_id": new_order.id, "estimated_wait": new_order.estimated_wait,
        "base_price": base_price, "dynamic_multiplier": multiplier,
        "final_price": final_price, "status": new_order.status
    }


def dispatch_order(order_id: int, db: Session):
    order = db.query(Order).filter(Order.id == order_id).first()
    if not order or order.status != "matching":
        return
    available_drivers = db.query(Driver).filter(Driver.status == "online").all()
    driver_scores = []
    for driver in available_drivers:
        dist = calculate_distance(order.pickup_x, order.pickup_y, driver.location_x, driver.location_y)
        if dist <= 20.0:
            score = calculate_driver_score(driver, dist)
            driver_scores.append((driver, dist, score))
    driver_scores.sort(key=lambda x: x[2], reverse=True)
    top_drivers = driver_scores[:5]
    order.estimated_wait = int(top_drivers[0][1] * 3) if top_drivers else 600
    db.commit()


@app.get("/api/passenger/orders")
def get_my_orders(current_user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    orders = db.query(Order).filter(Order.passenger_id == current_user.id).order_by(Order.created_at.desc()).all()
