@app.get("/api/driver/orders/available")
def get_available_orders(current_user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    if current_user.role != "driver":
        raise HTTPException(status_code=403, detail="Only drivers can access")
    driver = db.query(Driver).filter(Driver.user_id == current_user.id).first()
    if not driver:
        raise HTTPException(status_code=404, detail="Driver profile not found")
    orders = db.query(Order).filter(Order.status == "matching").all()
    result = []
    for o in orders:
        dist = calculate_distance(o.pickup_x, o.pickup_y, driver.location_x, driver.location_y)
        if dist <= 20.0:
            result.append({"id": o.id, "pickup_address": o.pickup_address, "dest_address": o.dest_address,
                           "distance": round(dist, 2), "price": o.final_price, "estimated_wait": o.estimated_wait})
    return result


@app.post("/api/driver/orders/{order_id}/accept")
def accept_order(order_id: int, current_user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    if current_user.role != "driver":
        raise HTTPException(status_code=403, detail="Only drivers can access")
    driver = db.query(Driver).filter(Driver.user_id == current_user.id).first()
    if not driver:
        raise HTTPException(status_code=404, detail="Driver profile not found")
    if driver.status != "online":
        raise HTTPException(status_code=400, detail="Driver not available")
    order = db.query(Order).filter(Order.id == order_id).first()
    if not order:
        raise HTTPException(status_code=404, detail="Order not found")
    if order.status != "matching":
        raise HTTPException(status_code=400, detail="Order no longer available")
    order.driver_id = driver.id
    order.status = "assigned"
    order.assigned_at = datetime.utcnow()
    driver.status = "busy"
    db.commit()
    return {"message": "Order accepted", "order_id": order.id}


@app.post("/api/driver/orders/{order_id}/reject")
def reject_order(order_id: int, current_user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    if current_user.role != "driver":
        raise HTTPException(status_code=403, detail="Only drivers can access")
    driver = db.query(Driver).filter(Driver.user_id == current_user.id).first()
    if driver:
        driver.rejection_rate = min(1.0, driver.rejection_rate + 0.05)
        db.commit()
    return {"message": "Order rejected"}


