# ============== Operator Routes ==============

@app.get("/api/operator/dashboard")
def get_dashboard(current_user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    if current_user.role != "operator":
        raise HTTPException(status_code=403, detail="Only operators can access")
    total_drivers = db.query(Driver).count()
    online_drivers = db.query(Driver).filter(Driver.status == "online").count()
    busy_drivers = db.query(Driver).filter(Driver.status == "busy").count()
    total_orders = db.query(Order).count()
    matching_orders = db.query(Order).filter(Order.status == "matching").count()
    active_orders = db.query(Order).filter(Order.status.in_(["assigned", "in_progress"])).count()
    completed_orders = db.query(Order).filter(Order.status == "completed").count()
    today = datetime.utcnow().replace(hour=0, minute=0, second=0, microsecond=0)
    today_orders = db.query(Order).filter(Order.created_at >= today).count()
    return {
        "drivers": {"total": total_drivers, "online": online_drivers, "busy": busy_drivers, "offline": total_drivers - online_drivers - busy_drivers},
        "orders": {"total": total_orders, "matching": matching_orders, "active": active_orders, "completed": completed_orders, "today": today_orders},
        "metrics": {"avg_wait_time": 300, "match_success_rate": 0.95}
    }


