@app.post("/api/ai/chat")
def ai_chat(msg: AIChatMessage, current_user: User = Depends(get_current_user), db: Session = Depends(get_db)):
    user_message = msg.message.lower()
    if AI_MOCK:
        if "订单" in user_message or "order" in user_message:
            orders = db.query(Order).filter(Order.passenger_id == current_user.id).order_by(Order.created_at.desc()).first()
            if orders:
                reply = f"您最近的订单是从 {orders.pickup_address} 到 {orders.dest_address}，当前状态是 {orders.status}。"
            else:
                reply = "您目前没有进行中的订单。"
        elif "退款" in user_message or "refund" in user_message:
            reply = "请问您是因为什么原因想要退款呢？\n1. 司机未到\n2. 行程有问题\n3. 其他原因"
        elif "投诉" in user_message or "complaint" in user_message:
            reply = "我理解您遇到了问题。请问您可以描述一下具体情况吗？我们会尽快处理。"
        elif "人工" in user_message or "human" in user_message:
